'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { ArrowRight, BookOpen, Loader2 } from 'lucide-react';

import { Button } from '@/components/ui/button';
import { createNotebook, listNotebooks } from '@/lib/notebook-api';
import { useNotebookWorkspaceUiStore } from '@/lib/stores/notebook-workspace-ui-store';

export default function NotebookEntryPage() {
  const router = useRouter();
  const recentNotebookId = useNotebookWorkspaceUiStore((state) => state.recentNotebookId);
  const [message, setMessage] = useState('正在恢复最近工作区');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      try {
        let notebooks = await listNotebooks();
        if (cancelled) return;
        if (!notebooks.length) {
          setMessage('正在创建默认智能笔记本');
          const created = await createNotebook({
            name: 'Untitled notebook',
            description: 'NotebookLM 风格智能笔记本',
          });
          if (cancelled) return;
          notebooks = [created];
        }
        const target =
          notebooks.find((row) => row.id === recentNotebookId)?.id || notebooks[0].id;
        setMessage(`进入 ${notebooks.find((row) => row.id === target)?.name || '笔记本工作台'}`);
        router.replace(`/notebook/${encodeURIComponent(target)}`);
      } catch (cause) {
        if (!cancelled) {
          setError(cause instanceof Error ? cause.message : '无法打开工作台');
        }
      }
    };
    void run();
    return () => {
      cancelled = true;
    };
  }, [recentNotebookId, router]);

  return (
    <div className="flex h-full items-center justify-center bg-[radial-gradient(circle_at_top,rgba(251,191,36,0.18),transparent_34%),linear-gradient(180deg,#1c1917_0%,#0c0a09_100%)]">
      <div className="w-full max-w-xl rounded-[2rem] border border-white/10 bg-white/5 px-8 py-10 text-center text-stone-100 backdrop-blur">
        <BookOpen className="mx-auto h-10 w-10" />
        <h1 className="mt-4 font-serif text-3xl font-semibold">Notebook Workspace</h1>
        <p className="mt-3 text-sm text-stone-300">{error || message}</p>
        {error ? (
          <div className="mt-6">
            <Button
              variant="outline"
              className="rounded-full border-white/15 bg-white/10 text-stone-100 hover:bg-white/15"
              onClick={() => router.refresh()}
            >
              <ArrowRight className="h-4 w-4" />
              重试
            </Button>
          </div>
        ) : (
          <div className="mt-6 inline-flex items-center gap-3 rounded-full border border-white/10 bg-white/10 px-4 py-2 text-sm text-stone-200">
            <Loader2 className="h-4 w-4 animate-spin" />
            准备 Sources、Chat、Studio 与 Notes
          </div>
        )}
      </div>
    </div>
  );
}
